"""
Step ID: step03
Step Name: prepare_analysis_dataset
RQ: results/ch7/7.7.3
Generated: 2026-01-09

PURPOSE:
Merge RAVLT and theta data into analysis-ready dataset with quality checks.
Compute correlation matrix to screen for multicollinearity issues.

EXPECTED INPUTS:
  - results/ch7/7.7.3/data/step01_ravlt_scores.csv
    Columns: ['UID', 'Total_z', 'Learning_z', 'LearningSlope_z', 'Recognition_z', ...]
  - results/ch7/7.7.3/data/step02_theta_scores.csv
    Columns: ['UID', 'theta_all', 'theta_standardized']

EXPECTED OUTPUTS:
  - results/ch7/7.7.3/data/step03_analysis_dataset.csv
    Columns: ['UID', 'Total_z', 'Learning_z', 'LearningSlope_z', 'Recognition_z', 'theta_all']
    Merged analysis-ready dataset (N=100 rows)
  - results/ch7/7.7.3/data/step03_correlation_matrix.csv
    Predictor intercorrelation matrix for multicollinearity screening

VALIDATION CRITERIA:
  - N=100 participants after merge
  - No missing values
  - Predictor correlations < 0.9 (multicollinearity threshold)

g_code REASONING:
- Approach: Inner merge on UID, select needed columns, compute correlations
- Why this approach: Ensures clean dataset for regression, detects multicollinearity early
- Data flow: RAVLT + theta -> merge -> select predictors + outcome -> correlations -> save
- Expected performance: <5 seconds

IMPLEMENTATION NOTES:
- Analysis tool: Custom merge (avoid tools function signature mismatch)
- Merge type: Inner join (only participants with both RAVLT and theta data)
- Multicollinearity check: VIF threshold 5.0, correlation threshold 0.9
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# RQ directory
RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step03_prepare_analysis_dataset.log"
OUTPUT_DATASET = RQ_DIR / "data" / "step03_analysis_dataset.csv"
OUTPUT_CORR = RQ_DIR / "data" / "step03_correlation_matrix.csv"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 03: Prepare Analysis Dataset")

        # =========================================================================
        # STEP 1: Load RAVLT Scores
        # =========================================================================
        log("[LOAD] Loading RAVLT scores...")

        ravlt_path = RQ_DIR / "data" / "step01_ravlt_scores.csv"
        ravlt_df = pd.read_csv(ravlt_path)

        log(f"[LOADED] {ravlt_path.name} ({len(ravlt_df)} participants, {len(ravlt_df.columns)} columns)")

        # =========================================================================
        # STEP 2: Load Theta Scores
        # =========================================================================
        log("[LOAD] Loading theta scores...")

        theta_path = RQ_DIR / "data" / "step02_theta_scores.csv"
        theta_df = pd.read_csv(theta_path)

        log(f"[LOADED] {theta_path.name} ({len(theta_df)} participants, {len(theta_df.columns)} columns)")

        # =========================================================================
        # STEP 3: Merge Datasets
        # =========================================================================
        log("[MERGE] Merging RAVLT and theta data on UID...")

        # Inner join: only participants with both RAVLT and theta data
        merged_df = pd.merge(ravlt_df, theta_df, on='UID', how='inner')

        log(f"[MERGED] {len(merged_df)} participants after merge")

        if len(merged_df) < 100:
            log(f"[WARNING] Expected 100 participants, found {len(merged_df)} after merge")
            log(f"[INFO] RAVLT: {len(ravlt_df)} participants, Theta: {len(theta_df)} participants")

        # =========================================================================
        # STEP 4: Select Analysis Columns
        # =========================================================================
        # Select only columns needed for regression:
        # - UID (identifier)
        # - Predictors: Total_z, Learning_z, LearningSlope_z, Recognition_z (standardized RAVLT)
        # - Outcome: theta_all (REMEMVR omnibus ability)
        log("[SELECT] Selecting analysis columns...")

        analysis_cols = ['UID', 'Total_z', 'Learning_z', 'LearningSlope_z', 'Forgetting_z', 'Recognition_z', 'PctRet_z', 'theta_all']
        analysis_df = merged_df[analysis_cols].copy()

        log(f"[SELECTED] {len(analysis_cols)} columns for analysis")

        # =========================================================================
        # STEP 5: Quality Checks
        # =========================================================================
        log("[VALIDATION] Running quality checks...")

        # Check for missing data
        n_missing = analysis_df.isnull().sum().sum()
        if n_missing > 0:
            log(f"[WARNING] {n_missing} missing values detected")
            log(f"[INFO] Missing by column:\n{analysis_df.isnull().sum()[analysis_df.isnull().sum() > 0]}")

            # Drop rows with missing values
            before_drop = len(analysis_df)
            analysis_df = analysis_df.dropna()
            after_drop = len(analysis_df)
            log(f"[INFO] Dropped {before_drop - after_drop} rows with missing values")
        else:
            log("[PASS] No missing values")

        # Check final sample size
        log(f"[INFO] Final sample size: N={len(analysis_df)}")

        # =========================================================================
        # STEP 6: Compute Correlation Matrix
        # =========================================================================
        log("[CORRELATIONS] Computing predictor intercorrelation matrix...")

        # Select only predictors (not UID or outcome)
        predictor_cols = ['Total_z', 'Learning_z', 'LearningSlope_z', 'Forgetting_z', 'Recognition_z', 'PctRet_z']
        corr_matrix = analysis_df[predictor_cols].corr()

        log("[COMPUTED] Correlation matrix")

        # Check for high correlations (multicollinearity warning)
        high_corr_threshold = 0.9
        high_corrs = []

        for i in range(len(predictor_cols)):
            for j in range(i+1, len(predictor_cols)):
                corr_val = corr_matrix.iloc[i, j]
                if abs(corr_val) > high_corr_threshold:
                    high_corrs.append((predictor_cols[i], predictor_cols[j], corr_val))

        if high_corrs:
            log(f"[WARNING] High correlations detected (>{high_corr_threshold}):")
            for pred1, pred2, corr_val in high_corrs:
                log(f"  {pred1} <-> {pred2}: r={corr_val:.3f}")
        else:
            log(f"[PASS] No correlations exceed {high_corr_threshold} threshold")

        # Display correlation matrix
        log("[INFO] Predictor correlation matrix:")
        for i, row in enumerate(predictor_cols):
            corr_str = "  " + row + ":"
            for j, col in enumerate(predictor_cols):
                corr_str += f" {corr_matrix.iloc[i,j]:6.3f}"
            log(corr_str)

        # =========================================================================
        # STEP 7: Save Outputs
        # =========================================================================
        log("[SAVE] Saving analysis dataset...")

        analysis_df.to_csv(OUTPUT_DATASET, index=False, encoding='utf-8')
        log(f"[SAVED] {OUTPUT_DATASET} ({len(analysis_df)} participants, {len(analysis_df.columns)} columns)")

        log("[SAVE] Saving correlation matrix...")
        corr_matrix.to_csv(OUTPUT_CORR, encoding='utf-8')
        log(f"[SAVED] {OUTPUT_CORR}")

        # =========================================================================
        # Summary Statistics
        # =========================================================================
        log("[SUMMARY] Descriptive statistics:")
        log(f"  Total_z: M={analysis_df['Total_z'].mean():.2f}, SD={analysis_df['Total_z'].std():.2f}")
        log(f"  Learning_z: M={analysis_df['Learning_z'].mean():.2f}, SD={analysis_df['Learning_z'].std():.2f}")
        log(f"  LearningSlope_z: M={analysis_df['LearningSlope_z'].mean():.2f}, SD={analysis_df['LearningSlope_z'].std():.2f}")
        log(f"  Forgetting_z: M={analysis_df['Forgetting_z'].mean():.2f}, SD={analysis_df['Forgetting_z'].std():.2f}")
        log(f"  Recognition_z: M={analysis_df['Recognition_z'].mean():.2f}, SD={analysis_df['Recognition_z'].std():.2f}")
        log(f"  PctRet_z: M={analysis_df['PctRet_z'].mean():.2f}, SD={analysis_df['PctRet_z'].std():.2f}")
        log(f"  theta_all: M={analysis_df['theta_all'].mean():.2f}, SD={analysis_df['theta_all'].std():.2f}")

        log("[SUCCESS] Step 03 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        import traceback
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
